import time
import textwrap
import shutil
import pathlib
import yaml
import json
import subprocess

from python_on_whales import docker

from Deadline.deadline_docker.constants import *
from Deadline.deadline_docker.utils import *

from dagster import (
    AssetIn,
    AssetExecutionContext,
    asset,
    Output,
    AssetMaterialization,
    MetadataValue,
)


@asset(
    group_name="Kitsu",
    compute_kind="python",
    ins={
        "env_base": AssetIn(),
    },
)
def build_kitsu(
        context: AssetExecutionContext,
        env_base: dict,
) -> str:
    """
    """

    docker_file = pathlib.Path(
        DOT_DOCKER_ROOT,
        "generations",
        env_base.get("GENERATION", "default"),
        "Dockerfiles",
        context.asset_key.path[-1],
        "Dockerfile",
    )

    tags = [
        f"{env_base.get('IMAGE_PREFIX')}/{context.asset_key.path[-1]}:latest",
        f"{env_base.get('IMAGE_PREFIX')}/{context.asset_key.path[-1]}:{str(time.time())}",
    ]

    # @formatter:off
    docker_file_str = textwrap.dedent("""
        # {auto_generated}
        # https://hub.docker.com/r/cgwire/cgwire
        FROM cgwire/cgwire:latest AS {image_name}
        LABEL authors="{AUTHOR}"
        
        #RUN tar -cvzf /var/lib/postgresql/14/main.tar.gz /var/lib/postgresql/14/main
        
        WORKDIR /opt/zou
        
        ENTRYPOINT ["/opt/zou/start_zou.sh"]
        CMD []
    """).format(
        auto_generated=f"AUTO-GENERATED by Dagster Asset {context.asset_key.path[-1]}",
        image_name=context.asset_key.path[-1],
        **env_base,
    )
    # @formatter:on

    shutil.rmtree(docker_file.parent, ignore_errors=True)

    docker_file.parent.mkdir(parents=True, exist_ok=True)

    with open(docker_file, "w") as fw:
        fw.write(docker_file_str)

    with open(docker_file, "r") as fr:
        docker_file_content = fr.read()

    stream = docker.build(
        context_path=docker_file.parent.as_posix(),
        cache=DOCKER_USE_CACHE,
        tags=tags,
        stream_logs=True,
    )

    log: str = ""

    for msg in stream:
        context.log.debug(msg)
        log += msg

    cmds_docker = compile_cmds(
        docker_file=docker_file,
        tag=tags[1],
    )

    yield Output(tags[1])

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            context.asset_key.path[-1]: MetadataValue.path(tags[1]),
            "docker_file": MetadataValue.md(f"```shell\n{docker_file_content}\n```"),
            **cmds_docker,
            "build_logs": MetadataValue.md(f"```shell\n{log}\n```"),
            "env_base": MetadataValue.json(env_base),
        },
    )


@asset(
    group_name="Kitsu",
    compute_kind="python",
    ins={
        "env_base": AssetIn(),
        "build_kitsu": AssetIn(),
    },
)
def compose_kitsu(
        context: AssetExecutionContext,
        env_base: dict,
        build_kitsu: str,
) -> dict:
    """
    """

    cmd_docker_run = f"docker run --rm --interactive --tty {build_kitsu} /bin/bash"

    volumes = [
        f"{env_base.get('NFS_ENTRY_POINT')}:{env_base.get('NFS_ENTRY_POINT')}",
        f"{env_base.get('NFS_ENTRY_POINT')}:{env_base.get('NFS_ENTRY_POINT_LNS')}",
    ]

    kitsu_db_dir_host = pathlib.Path(env_base.get("KITSU_DATABASE_INSTALL_DESTINATION"))
    kitsu_db_dir_host.mkdir(parents=True, exist_ok=True)

    # sudo chown 105:105 KitsuPostgres
    # Concept: /usr/bin/sshpass -eENV_VAR /usr/bin/ssh "echo $ENV_VAR | sudo -S <cmd>"
    # Because shutil.chown cannot sudo
    mongo_uid = 105
    mongo_gid = 105

    cmd_chown = [
        shutil.which("sshpass"),
        "-eSSH_PASS",
        "ssh",
        f"{env_base.get('SSH_USER')}@{env_base.get('SSH_HOST')}",
        f"\"echo $SSH_PASS | sudo -S chown {mongo_uid}:{mongo_gid} {kitsu_db_dir_host.as_posix()}\"",
    ]

    cmd_chown_str = cmd_list_to_str(cmd_chown)

    context.log.info(f"{cmd_chown_str = }")

    stdout_stderr = {
            "stdout": MetadataValue.md(f"```shell\nNone\n```"),
            "stderr": MetadataValue.md(f"```shell\nNone\n```"),
    }

    if not KITSUDB_INSIDE_CONTAINER:
        kitsu_db_dir_host.mkdir(parents=True, exist_ok=True)

        context.log.info(f"Setting ownership of {kitsu_db_dir_host.as_posix()}...")

        proc = subprocess.Popen(
            args=cmd_chown_str,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            shell=True,
            env={
                "SSH_PASS": env_base.get('SSH_PASS'),
            }
        )

        stdout, stderr = proc.communicate()

        stdout_stderr = {
                "stdout": MetadataValue.md(f"```shell\n{stdout.decode(encoding='utf-8')}\n```"),
                "stderr": MetadataValue.md(f"```shell\n{stderr.decode(encoding='utf-8')}\n```"),
        }

        # helpers.iterate_fds(
        #     (
        #         proc.stderr,
        #         proc.stdout,
        #     ),
        #     (
        #         context.log.warning,
        #         context.log.info,
        #     )
        # )

        volumes.insert(
            0,
            f"{env_base.get('KITSU_POSTGRESQL_CONF')}:/etc/postgresql/14/main/postgresql.conf:ro",
        )

    docker_dict = {
        "services": {
            "kitsu": {
                "container_name": "kitsu",
                "hostname": "kitsu",
                "domainname": env_base.get("ROOT_DOMAIN"),
                "restart": "always",
                "image": build_kitsu,
                "volumes": volumes,
                "ports": [
                    f"{env_base.get('KITSU_PORT_HOST')}:{env_base.get('KITSU_PORT_CONTAINER')}",
                ],
            },
        },
    }

    docker_yaml = yaml.dump(docker_dict)

    yield Output(docker_dict)

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            context.asset_key.path[-1]: MetadataValue.json(docker_dict),
            "docker_dict": MetadataValue.md(f"```json\n{json.dumps(docker_dict, indent=2)}\n```"),
            "docker_yaml": MetadataValue.md(f"```yaml\n{docker_yaml}\n```"),
            "cmd_docker_run": MetadataValue.path(cmd_docker_run),
            "cmd_chown": MetadataValue.path(cmd_chown_str),
            **stdout_stderr,
            "env_base": MetadataValue.json(env_base),
        },
    )